const defaultVenue = 'Aurora (5. floor), TUKE'
const defaultAddress = 'Letna 9, Kosice'

function createEvent({
  number,
  date = '',
  time = '17:00',
  title,
  subtitle,
  intro,
  summary,
  talks,
  demoPoints,
  tags,
  venue = defaultVenue,
  address = defaultAddress
}) {
  return {
    id: `meetup-${number}`,
    number,
    title,
    subtitle,
    status: 'past',
    featured: false,
    isTba: false,
    date,
    time,
    venue,
    address,
    intro,
    summary,
    talks,
    demoPoints,
    tags
  }
}

